sprite_code.bg:
// Twilight Steampunk Cityscape Background
// Dark Indigo Sky Gradient
for(var y=0; y<85; y++) {
  var g = y / 85;
  for(var x=0; x<PW; x++) {
    px(x, y, Math.floor(20 + g*30), Math.floor(15 + g*25), Math.floor(60 + g*40), 'sky');
  }
}
// Rooftop Ground (Dark Slate)
for(var y=85; y<PH; y++) {
  var g = (y-85) / (PH-85);
  for(var x=0; x<PW; x++) {
    var n = Math.sin(x*0.2) * 2 + Math.random() * 3;
    px(x, y, Math.floor(40 + n), Math.floor(42 + n), Math.floor(55 + n), 'ground');
  }
}
// Distant City Silhouettes
for(var i=0; i<6; i++) {
  var bx = 20 + i*50; var bh = 30 + Math.random()*40;
  rect(bx, 85-bh, 35, bh, 35, 30, 50, 'ground.buildings');
  // Tiny Windows in distant buildings
  px(bx+5, 85-bh+5, 255, 200, 100, 'ground.buildings.windows');
  px(bx+25, 85-bh+15, 255, 200, 100, 'ground.buildings.windows');
}
// Swirling Lavender Smog
for(var i=0; i<5; i++) {
  var sx = 50 + i*60; var sy = 40 + i*10;
  circ(sx, sy, 12, 180, 160, 210, 'sky.smog');
  circ(sx+5, sy-2, 8, 200, 185, 230, 'sky.smog');
}

sprite_code.cat_01:
const eid = 'cat_01';
const cx = 140, cy = 60;
// Mechanical Body (Bronze)
ellip(cx, cy, 10, 6, 120, 70, 30, eid+'.body');
ellip(cx, cy, 8, 5, 160, 100, 50, eid+'.body');
ellip(cx-2, cy-1, 5, 3, 190, 130, 70, eid+'.body.highlight');
// Joints (Silver)
circ(cx-6, cy+4, 2, 180, 180, 190, eid+'.body.joints');
circ(cx+6, cy+4, 2, 180, 180, 190, eid+'.body.joints');
// Head
circ(cx-10, cy-4, 6, 140, 90, 40, eid+'.head');
circ(cx-10, cy-4, 5, 170, 110, 60, eid+'.head');
// Glowing Teal Eyes
circ(cx-13, cy-5, 2, 0, 180, 180, eid+'.head.eyes.left');
circ(cx-8, cy-5, 2, 0, 180, 180, eid+'.head.eyes.right');
px(cx-14, cy-6, 200, 255, 255, eid+'.head.eyes.left');
px(cx-9, cy-6, 200, 255, 255, eid+'.head.eyes.right');
// Ears (Triangular)
tri(cx-15, cy-8, cx-14, cy-14, cx-12, cy-8, 140, 90, 40, eid+'.head.ears.left');
tri(cx-8, cy-8, cx-7, cy-14, cx-5, cy-8, 140, 90, 40, eid+'.head.ears.right');
// Segmented Brass Tail
for(var i=0; i<5; i++) {
  circ(cx+10+i*2, cy-2-i*2, 2, 140, 100, 40, eid+'.tail');
  circ(cx+10+i*2, cy-2-i*2, 1, 190, 150, 70, eid+'.tail');
}
// Legs
rect(cx-6, cy+5, 2, 6, 130, 80, 35, eid+'.legs.front');
rect(cx+5, cy+5, 2, 6, 130, 80, 35, eid+'.legs.back');
// Rivet Details
for(var i=0; i<4; i++) px(cx-4+i*3, cy+2, 60, 40, 20, eid+'.body.rivets');
// Whiskers (Copper Wire)
line(cx-16, cy-3, cx-20, cy-3, 180, 120, 60, eid+'.head.whiskers');
line(cx-16, cy-2, cx-20, cy-1, 180, 120, 60, eid+'.head.whiskers');

sprite_code.wire_01:
const eid = 'wire_01';
const cx = 140, cy = 65;
// Braided Copper Wire
thickLine(0, 75, 280, 55, 3, 110, 60, 30, eid);
thickLine(0, 75, 280, 55, 1, 180, 110, 50, eid+'.highlight');
// Spiral Twist Pattern
for(var x=0; x<280; x+=10) {
  var wy = 75 - (x/280)*20;
  line(x, wy-1, x+5, wy+1, 80, 40, 20, eid+'.texture');
}
// Blue Static Electricity Sparks
for(var i=0; i<8; i++) {
  var sx = Math.random()*280;
  var sy = 75 - (sx/280)*20 + (Math.random()*4-2);
  px(sx, sy, 100, 200, 255, eid+'.sparks');
  px(sx+1, sy-1, 255, 255, 255, eid+'.sparks');
}

sprite_code.lamp_01:
const eid = 'lamp_01';
const cx = 60, cy = 140;
// Iron Post
rect(cx-2, cy-30, 4, 70, 40, 40, 45, eid+'.post');
rect(cx-1, cy-30, 1, 70, 60, 60, 70, eid+'.post.highlight');
// Decorative Curls
arc(cx-5, cy-25, 4, 0, 3, 40, 40, 45, eid+'.post.curls');
arc(cx+5, cy-25, 4, 0, 3, 40, 40, 45, eid+'.post.curls');
// Glass Globe
circ(cx, cy-40, 12, 80, 60, 40, eid+'.globe');
circ(cx, cy-40, 10, 255, 180, 50, eid+'.globe.glow');
circ(cx, cy-40, 7, 255, 220, 100, eid+'.globe.inner');
// Fireflies (Tiny dots)
for(var i=0; i<6; i++) {
  px(cx-4+Math.random()*8, cy-44+Math.random()*8, 255, 255, 200, eid+'.globe.fireflies');
}
// Wrought Iron Cap
tri(cx-13, cy-48, cx, cy-60, cx+13, cy-48, 30, 30, 35, eid+'.cap');
circ(cx, cy-60, 2, 40, 40, 45, eid+'.cap.tip');
// Ground Base
ellip(cx, cy+40, 8, 3, 30, 30, 35, eid+'.base');

sprite_code.chimney_01:
const eid = 'chimney_01';
const cx = 220, cy = 120;
// Brick Structure
rect(cx-15, cy-40, 30, 100, 120, 50, 40, eid+'.bricks');
// Staggered Brick Pattern
for(var y=cy-40; y<cy+60; y+=8) {
  line(cx-15, y, cx+15, y, 80, 30, 20, eid+'.bricks.lines');
  for(var x=cx-15; x<cx+15; x+=10) {
    var offset = (Math.floor((y-cy+40)/8) % 2) * 5;
    line(x+offset, y, x+offset, y+8, 80, 30, 20, eid+'.bricks.lines');
  }
}
// Sooty Top
rect(cx-17, cy-45, 34, 10, 50, 45, 45, eid+'.top');
rect(cx-16, cy-44, 32, 8, 70, 65, 65, eid+'.top.rim');
// Lavender Steam
for(var i=0; i<4; i++) {
  var sy = cy-60-i*15;
  var sx = cx + Math.sin(i)*10;
  circ(sx, sy, 10-i, 180, 140, 200, eid+'.steam');
  circ(sx+2, sy-2, 7-i, 210, 180, 230, eid+'.steam');
}
// Texture/Cracks
px(cx-5, cy+10, 60, 20, 10, eid+'.bricks.detail');
px(cx+8, cy-15, 60, 20, 10, eid+'.bricks.detail');
px(cx, cy+30, 60, 20, 10, eid+'.bricks.detail');
